import { View, Text, Pressable, ScrollView } from 'react-native';
import { Stack, useLocalSearchParams, router } from 'expo-router';
import { useEffect, useState } from 'react';
import { Trophy, TrendingUp, AlertCircle, Home, RotateCcw, Sparkles } from 'lucide-react-native';
import { useGamificationStore } from '../../store/gamificationStore';
import { useAuth } from '../../hooks/useAuth';
import { sanityClient } from '../../lib/sanity';

// Mock AI feedback - will be generated by AI API in production
const MOCK_FEEDBACK = {
  overallScore: 85,
  rating: 'Excellent',
  xpEarned: 150,
  gemsEarned: 25,
  strengths: [
    'Clear and concise communication',
    'Strong examples from past experience',
    'Confident delivery and tone',
  ],
  improvements: [
    'Provide more specific metrics in answers',
    'Elaborate more on technical skills',
  ],
  questionFeedback: [
    {
      question: 'Tell me about yourself and your background.',
      score: 90,
      feedback: 'Great introduction with clear career progression. Consider adding more specific achievements.',
    },
    {
      question: 'What are your greatest strengths?',
      score: 85,
      feedback: 'Good self-awareness. Examples were relevant but could be more detailed.',
    },
    {
      question: 'Describe a challenging situation.',
      score: 80,
      feedback: 'Good structure using STAR method. Impact could be quantified better.',
    },
  ],
};

export default function ResultsScreen() {
  const params = useLocalSearchParams();
  const interviewId = params.id as string;
  const interviewTitle = params.title as string;
  const answersJson = params.answers as string;

  const [showDetailedFeedback, setShowDetailedFeedback] = useState(false);
  const { addXP, addGems, updateStreak } = useGamificationStore();
  const { user } = useAuth();

  // Award XP, gems, and save completion on mount
  useEffect(() => {
    const saveCompletion = async () => {
      if (!user?.id) {
        console.warn('Cannot save completion: no user ID');
        return;
      }

      try {
        const answers = answersJson ? JSON.parse(answersJson) : [];
        
        await sanityClient.create({
          _type: 'interviewCompletion',
          user: { _ref: user.id, _type: 'reference' },
          interview: { _ref: interviewId, _type: 'reference' },
          score: MOCK_FEEDBACK.overallScore,
          rating: MOCK_FEEDBACK.rating,
          answers,
          feedback: MOCK_FEEDBACK,
          xpEarned: MOCK_FEEDBACK.xpEarned,
          gemsEarned: MOCK_FEEDBACK.gemsEarned,
          completedAt: new Date().toISOString(),
        });

        console.log('Interview completion saved successfully');
      } catch (error) {
        console.error('Failed to save interview completion:', error);
        // Non-critical error - user still received rewards
      }
    };

    addXP(MOCK_FEEDBACK.xpEarned);
    addGems(MOCK_FEEDBACK.gemsEarned);
    updateStreak();
    saveCompletion();
  }, [user?.id, interviewId, answersJson]);

  const getRatingColor = (rating: string) => {
    switch (rating) {
      case 'Excellent':
        return 'text-green-600';
      case 'Good':
        return 'text-blue-600';
      case 'Fair':
        return 'text-yellow-600';
      default:
        return 'text-gray-600';
    }
  };

  const handlePracticeAgain = () => {
    router.replace({
      pathname: '/interview/mode',
      params: { id: interviewId, title: interviewTitle },
    });
  };

  const handleBackToHome = () => {
    router.replace('/(tabs)');
  };

  return (
    <View className="flex-1 bg-gray-50">
      <Stack.Screen
        options={{
          title: 'Interview Results',
          headerBackTitle: 'Back',
          headerLeft: () => null,
        }}
      />

      <ScrollView className="flex-1">
        {/* Success Header */}
        <View className="bg-gradient-to-b from-green-50 to-white px-6 py-8 items-center border-b border-gray-200">
          <View className="w-20 h-20 bg-green-100 rounded-full items-center justify-center mb-4">
            <Trophy size={40} color="#16a34a" />
          </View>
          <Text className="text-2xl font-bold text-gray-900 mb-2">
            Interview Complete!
          </Text>
          <Text className="text-base text-gray-600 text-center">
            {interviewTitle}
          </Text>
        </View>

        {/* Score Card */}
        <View className="mx-4 mt-4 p-6 bg-white rounded-xl border border-gray-200 shadow-sm">
          <View className="items-center mb-6">
            <Text className="text-6xl font-bold text-gray-900 mb-2">
              {MOCK_FEEDBACK.overallScore}
            </Text>
            <Text className={`text-xl font-semibold ${getRatingColor(MOCK_FEEDBACK.rating)}`}>
              {MOCK_FEEDBACK.rating}
            </Text>
          </View>

          {/* Rewards */}
          <View className="flex-row justify-around pt-4 border-t border-gray-200">
            <View className="items-center">
              <View className="flex-row items-center gap-2 mb-1">
                <Sparkles size={20} color="#3b82f6" />
                <Text className="text-2xl font-bold text-blue-600">
                  +{MOCK_FEEDBACK.xpEarned}
                </Text>
              </View>
              <Text className="text-sm text-gray-600">XP Earned</Text>
            </View>

            <View className="items-center">
              <View className="flex-row items-center gap-2 mb-1">
                <Text className="text-2xl font-bold text-amber-600">
                  +{MOCK_FEEDBACK.gemsEarned}
                </Text>
                <Text className="text-2xl">💎</Text>
              </View>
              <Text className="text-sm text-gray-600">Gems Earned</Text>
            </View>
          </View>
        </View>

        {/* Strengths */}
        <View className="mx-4 mt-4 p-4 bg-white rounded-xl border border-gray-200 shadow-sm">
          <View className="flex-row items-center gap-2 mb-3">
            <TrendingUp size={20} color="#16a34a" />
            <Text className="text-lg font-semibold text-gray-900">
              Your Strengths
            </Text>
          </View>
          {MOCK_FEEDBACK.strengths.map((strength, index) => (
            <View key={index} className="flex-row items-start gap-2 mb-2">
              <Text className="text-green-600 mt-1">✓</Text>
              <Text className="flex-1 text-base text-gray-700">
                {strength}
              </Text>
            </View>
          ))}
        </View>

        {/* Areas for Improvement */}
        <View className="mx-4 mt-4 p-4 bg-white rounded-xl border border-gray-200 shadow-sm">
          <View className="flex-row items-center gap-2 mb-3">
            <AlertCircle size={20} color="#f59e0b" />
            <Text className="text-lg font-semibold text-gray-900">
              Areas for Improvement
            </Text>
          </View>
          {MOCK_FEEDBACK.improvements.map((improvement, index) => (
            <View key={index} className="flex-row items-start gap-2 mb-2">
              <Text className="text-amber-600 mt-1">•</Text>
              <Text className="flex-1 text-base text-gray-700">
                {improvement}
              </Text>
            </View>
          ))}
        </View>

        {/* Detailed Feedback Toggle */}
        <View className="mx-4 mt-4">
          <Pressable
            className="py-3 bg-blue-50 rounded-lg items-center active:bg-blue-100"
            onPress={() => setShowDetailedFeedback(!showDetailedFeedback)}
          >
            <Text className="text-blue-600 font-medium">
              {showDetailedFeedback ? 'Hide' : 'View'} Detailed Feedback
            </Text>
          </Pressable>
        </View>

        {/* Detailed Question Feedback */}
        {showDetailedFeedback && (
          <View className="mx-4 mt-4 mb-4 space-y-3">
            {MOCK_FEEDBACK.questionFeedback.map((item, index) => (
              <View
                key={index}
                className="p-4 bg-white rounded-xl border border-gray-200 shadow-sm"
              >
                <View className="flex-row items-center justify-between mb-2">
                  <Text className="text-sm font-semibold text-gray-900">
                    Question {index + 1}
                  </Text>
                  <View className="px-3 py-1 bg-blue-100 rounded-full">
                    <Text className="text-sm font-bold text-blue-600">
                      {item.score}
                    </Text>
                  </View>
                </View>
                <Text className="text-sm text-gray-700 mb-2">
                  {item.question}
                </Text>
                <Text className="text-sm text-gray-600 italic">
                  {item.feedback}
                </Text>
              </View>
            ))}
          </View>
        )}

        {/* Action Buttons */}
        <View className="px-4 py-6 gap-3">
          <Pressable
            className="py-4 rounded-lg items-center bg-blue-500 active:bg-blue-600"
            onPress={handlePracticeAgain}
          >
            <View className="flex-row items-center gap-2">
              <RotateCcw size={20} color="white" />
              <Text className="text-white font-semibold text-base">
                Practice Again
              </Text>
            </View>
          </Pressable>

          <Pressable
            className="py-4 rounded-lg items-center bg-white border border-gray-300 active:bg-gray-50"
            onPress={handleBackToHome}
          >
            <View className="flex-row items-center gap-2">
              <Home size={20} color="#6b7280" />
              <Text className="text-gray-700 font-medium text-base">
                Back to Home
              </Text>
            </View>
          </Pressable>
        </View>
      </ScrollView>
    </View>
  );
}
